import subprocess

def parse(fn):
    seqs={}; name=None
    for line in open(fn):
        line=line.rstrip('\n')
        if not line.strip(): continue
        if line.startswith('>'): name=line[1:].strip(); seqs[name]=''
        elif not line.startswith('#'): seqs[name]+=line.strip().lower()
    return seqs
s=parse('/app/sequences.fasta')
inp=s['input']; out=s['output']; egfp=s['egfp']; flag=s['flag']; snap=s['snap']

comp={'a':'t','t':'a','g':'c','c':'g'}
def rc(x): return ''.join(comp[b] for b in reversed(x))

def tm(seq):
    r=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq.upper()],
                     capture_output=True,text=True)
    return float(r.stdout.strip())

# Native annealing anchor sequences (sense) for each primer end
# For fwd primers: anneal = region[0:L]
# For rev primers: anneal(sense) = region[len-L:], primer = rc(that)
frag = {
 'input': dict(
    fwd_region = (inp[691:691+45]),                 # backbone start, 5'
    rev_region = (inp[214-45:214]),                 # backbone end (ends at inp[213])
 ),
 'egfp': dict(
    fwd_region = egfp[8:8+45],
    rev_region = egfp[len(egfp)-3-45:len(egfp)-3],
 ),
 'flag': dict(
    fwd_region = flag[7:7+40],
    rev_region = flag[len(flag)-3-40:len(flag)-3],
 ),
 'snap': dict(
    fwd_region = snap[7:7+45],
    rev_region = snap[len(snap)-3-45:len(snap)-3],
 ),
}

def choose(region, is_fwd, target=65):
    # region is sense; pick L in [15,36]; anneal seq for tm:
    best=None
    for L in range(15,37):
        if L>len(region): break
        if is_fwd: aseq=region[:L]
        else: aseq=region[len(region)-L:]
        t=tm(aseq)
        cand=(abs(t-target),L,t,aseq)
        if 58<=t<=72:
            if best is None or cand<best: best=cand
    return best  # (score,L,tm,aseq)

for name,d in frag.items():
